SELECT


FROM t_seatunnel_web_streaming_job_instance i

LEFT JOIN t_seatunnel_web_streaming_job_definition d
ON i.job_definition_id = d.id

LEFT JOIN t_seatunnel_web_streaming_job_metrics_current m
ON i.id = m.job_instance_id





            AND i.id = #{dto.id}



            AND i.job_definition_id = #{dto.jobDefinitionId}



            AND i.job_status = #{dto.jobStatus}



            AND i.run_mode = #{dto.runMode}



            AND (
            d.job_name LIKE CONCAT('%', #{dto.keyword}, '%')
            OR CAST(i.engine_job_id AS CHAR) LIKE CONCAT('%', #{dto.keyword}, '%')
            OR i.error_message LIKE CONCAT('%', #{dto.keyword}, '%')
            OR i.log_path LIKE CONCAT('%', #{dto.keyword}, '%')
            )



            AND i.create_time  >=  #{dto.queryStartTime}



            AND i.create_time  <=  #{dto.queryEndTime}





ORDER BY
i.create_time DESC,
i.id DESC
